    const n = points.length;
    const slopeMap = new Map();

    // Function to calculate the slope between two points
    function getSlope(p1, p2) {
        const dx = p2[0] - p1[0];
        const dy = p2[1] - p1[1];
        if (dx === 0 && dy === 0) return null; // same point
        if (dx === 0) return 'inf'; // vertical line
        // Simplify the slope to a unique representation
        const gcd = (a, b) => {
            while (b) {
                const temp = b;
                b = a % b;
                a = temp;
            }
            return a;
        };
        const g = gcd(Math.abs(dx), Math.abs(dy));
        const simplifiedDx = dx / g;
        const simplifiedDy = dy / g;
        return `${simplifiedDy}/${simplifiedDx}`;
    }

    // Count all pairs of points and their slopes
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const slope = getSlope(points[i], points[j]);
            if (!slopeMap.has(slope)) {
                slopeMap.set(slope, 0);
            }
            slopeMap.set(slope, slopeMap.get(slope) + 1);
        }
    }

    // Calculate the number of trapezoids
    let trapezoidCount = 0;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const slope1 = getSlope(points[i], points[j]);
            for (let k = j + 1; k < n; k++) {
                const slope2 = getSlope(points[j], points[k]);
